42: 
43: // Manages subscriptions to one or more type of resource. The logical protocol
44: // state of those subscription(s) is handled by SubscriptionState.
45: // This class owns the GrpcStream used to talk to the server, maintains queuing
46: // logic to properly order the subscription(s)' various messages, and allows
47: // starting/stopping/pausing of the subscriptions.
48: //
49: // @tparam S SubscriptionState state type, either SotwSubscriptionState or DeltaSubscriptionState
50: // @tparam F SubscriptionStateFactory type, either SotwSubscriptionStateFactory or
51: // DeltaSubscriptionStateFactory
52: // @tparam RQ Xds request type, either envoy::service::discovery::v3::DiscoveryRequest or
53: // envoy::service::discovery::v3::DeltaDiscoveryRequest
54: // @tparam RS Xds response type, either envoy::service::discovery::v3::DiscoveryResponse or
55: // envoy::service::discovery::v3::DeltaDiscoveryResponse
56: //
57: template <class S, class F, class RQ, class RS>
58: class GrpcMuxImpl : public GrpcStreamCallbacks<RS>,
59:                     public GrpcMux,
60:                     public ShutdownableMux,
61:                     Logger::Loggable<Logger::Id::config> {
62: public:
63:   GrpcMuxImpl(std::unique_ptr<F> subscription_state_factory, GrpcMuxContext& grpc_mux_context);
64: 
65:   ~GrpcMuxImpl() override;
66: 
67:   // Causes all GrpcMuxImpl objects to stop sending any messages on `grpc_stream_` to fix a crash
68:   // on Envoy shutdown due to dangling pointers. This may not be the ideal fix; it is probably
69:   // preferable for the `ServerImpl` to cause all configuration subscriptions to be shutdown, which
70:   // would then cause all `GrpcMuxImpl` to be destructed.
71:   // TODO: figure out the correct fix: https://github.com/envoyproxy/envoy/issues/15072.
72:   static void shutdownAll();
73: 
74:   void shutdown() override { shutdown_ = true; }
75:   bool isShutdown() { return shutdown_; }
76: 
77:   // TODO (dmitri-d) return a naked pointer instead of the wrapper once the legacy mux has been
78:   // removed and the mux interface can be changed
79:   Config::GrpcMuxWatchPtr addWatch(const std::string& type_url,
80:                                    const absl::flat_hash_set<std::string>& resources,
81:                                    SubscriptionCallbacks& callbacks,
82:                                    OpaqueResourceDecoderSharedPtr resource_decoder,
83:                                    const SubscriptionOptions& options) override;
84:   void updateWatch(const std::string& type_url, Watch* watch,
85:                    const absl::flat_hash_set<std::string>& resources,
86:                    const SubscriptionOptions& options);
87:   void removeWatch(const std::string& type_url, Watch* watch);
88: 
89:   ScopedResume pause(const std::string& type_url) override;
90:   ScopedResume pause(const std::vector<std::string> type_urls) override;
91:   void start() override;
92:   const absl::flat_hash_map<std::string, std::unique_ptr<S>>& subscriptions() const {
93:     return subscriptions_;
94:   }
95: 
96:   // GrpcStreamCallbacks
97:   void onStreamEstablished() override { handleEstablishedStream(); }
98:   void onEstablishmentFailure(bool next_attempt_may_send_initial_resource_version) override {
99:     handleStreamEstablishmentFailure(next_attempt_may_send_initial_resource_version);
100:   }
101:   void onWriteable() override { trySendDiscoveryRequests(); }
102:   void onDiscoveryResponse(std::unique_ptr<RS>&& message,
103:                            ControlPlaneStats& control_plane_stats) override {
104:     genericHandleResponse(message->type_url(), *message, control_plane_stats);
105:   }
106: 
107:   absl::Status
108:   updateMuxSource(Grpc::RawAsyncClientSharedPtr&& primary_async_client,
109:                   Grpc::RawAsyncClientSharedPtr&& failover_async_client, Stats::Scope& scope,
110:                   BackOffStrategyPtr&& backoff_strategy,
111:                   const envoy::config::core::v3::ApiConfigSource& ads_config_source) override;
112: 
113:   EdsResourcesCacheOptRef edsResourcesCache() override {
114:     return makeOptRefFromPtr(eds_resources_cache_.get());
115:   }
116: 
117:   GrpcStreamInterface<RQ, RS>& grpcStreamForTest() {
118:     // TODO(adisuissa): Once envoy.restart_features.xds_failover_support is deprecated,
119:     // return grpc_stream_.currentStreamForTest() directly (defined in GrpcMuxFailover).
120:     if (Runtime::runtimeFeatureEnabled("envoy.restart_features.xds_failover_support")) {
121:       return dynamic_cast<GrpcMuxFailover<RQ, RS>*>(grpc_stream_.get())->currentStreamForTest();
122:     }
123:     return *grpc_stream_.get();
124:   }
125: 
126: protected:
127:   class WatchImpl : public Envoy::Config::GrpcMuxWatch {
128:   public:
129:     WatchImpl(const std::string& type_url, Watch* watch, GrpcMuxImpl& parent,
130:               const SubscriptionOptions& options)
131:         : type_url_(type_url), watch_(watch), parent_(parent), options_(options) {}
132: 
133:     ~WatchImpl() override { remove(); }
134: 
135:     void remove() {
136:       if (watch_) {
137:         parent_.removeWatch(type_url_, watch_);
138:         watch_ = nullptr;
139:       }
140:     }
141: 
142:     void update(const absl::flat_hash_set<std::string>& resources) override {
143:       parent_.updateWatch(type_url_, watch_, resources, options_);
144:     }
145: 
146:   private:
147:     const std::string type_url_;
148:     Watch* watch_;
149:     GrpcMuxImpl& parent_;
150:     const SubscriptionOptions options_;
151:   };
152: 
153:   void sendGrpcMessage(RQ& msg_proto, S& sub_state);
154:   void maybeUpdateQueueSizeStat(uint64_t size) { grpc_stream_->maybeUpdateQueueSizeStat(size); }
155:   bool grpcStreamAvailable() { return grpc_stream_->grpcStreamAvailable(); }
156:   bool rateLimitAllowsDrain() { return grpc_stream_->checkRateLimitAllowsDrain(); }
157:   void sendMessage(RQ& msg_proto) { grpc_stream_->sendMessage(msg_proto); }
158: 
159:   S& subscriptionStateFor(const std::string& type_url);
160:   WatchMap& watchMapFor(const std::string& type_url);
161:   void handleEstablishedStream();
162:   void handleStreamEstablishmentFailure(bool next_attempt_may_send_initial_resource_version);
163:   // May modify the order of the resources in response_proto to put all the
164:   // non-heartbeat resources first.
165:   void genericHandleResponse(const std::string& type_url, RS& response_proto,
166:                              ControlPlaneStats& control_plane_stats);
167:   void trySendDiscoveryRequests();
168:   bool skipSubsequentNode() const { return skip_subsequent_node_; }
169:   bool anyRequestSentYetInCurrentStream() const { return any_request_sent_yet_in_current_stream_; }
170:   void setAnyRequestSentYetInCurrentStream(bool value) {
171:     any_request_sent_yet_in_current_stream_ = value;
172:   }
173:   const LocalInfo::LocalInfo& localInfo() const { return local_info_; }
174: 
175:   virtual absl::string_view methodName() const PURE;
176: 
177: private:
178:   // Helper function to create the grpc_stream_ object.
179:   // TODO(adisuissa): this should be removed when envoy.restart_features.xds_failover_support
180:   // is deprecated.
181:   std::unique_ptr<GrpcStreamInterface<RQ, RS>>
182:   createGrpcStreamObject(Grpc::RawAsyncClientSharedPtr&& async_client,
183:                          Grpc::RawAsyncClientSharedPtr&& failover_async_client,
184:                          const Protobuf::MethodDescriptor& service_method, Stats::Scope& scope,
185:                          BackOffStrategyPtr&& backoff_strategy,
186:                          const RateLimitSettings& rate_limit_settings);
187: 
188:   // Checks whether external conditions allow sending a DeltaDiscoveryRequest. (Does not check
189:   // whether we *want* to send a (Delta)DiscoveryRequest).
190:   bool canSendDiscoveryRequest(const std::string& type_url);
191: 
192:   // Checks whether we have something to say in a (Delta)DiscoveryRequest, which can be an ACK
193:   // and/or a subscription update. (Does not check whether we *can* send that
194:   // (Delta)DiscoveryRequest). Returns the type_url we should send the DeltaDiscoveryRequest for (if
195:   // any). First, prioritizes ACKs over non-ACK subscription interest updates. Then, prioritizes
196:   // non-ACK updates in the order the various types of subscriptions were activated (as tracked by
197:   // subscription_ordering_).
198:   absl::optional<std::string> whoWantsToSendDiscoveryRequest();
199: 
200:   // Invoked when dynamic context parameters change for a resource type.
201:   void onDynamicContextUpdate(absl::string_view resource_type_url);
202: 
203:   Event::Dispatcher& dispatcher_;
204:   // Multiplexes the stream to the primary and failover sources.
205:   // TODO(adisuissa): Once envoy.restart_features.xds_failover_support is deprecated,
206:   // convert from unique_ptr<GrpcStreamInterface> to GrpcMuxFailover directly.
207:   std::unique_ptr<GrpcStreamInterface<RQ, RS>> grpc_stream_;
208: 
209:   // Resource (N)ACKs we're waiting to send, stored in the order that they should be sent in. All
210:   // of our different resource types' ACKs are mixed together in this queue. See class for
211:   // description of how it interacts with pause() and resume().
212:   PausableAckQueue pausable_ack_queue_;
213: 
214:   // Makes SubscriptionStates, to be held in the subscriptions_ map. Whether this GrpcMux is doing
215:   // delta or state of the world xDS is determined by which concrete subclass this variable gets.
216:   std::unique_ptr<F> subscription_state_factory_;
217: 
218:   // Map key is type_url.
219:   // Only addWatch() should insert into these maps.
220:   absl::flat_hash_map<std::string, std::unique_ptr<S>> subscriptions_;
221:   absl::flat_hash_map<std::string, std::unique_ptr<WatchMap>> watch_maps_;
222: 
223:   // Determines the order of initial discovery requests. (Assumes that subscriptions are added
224:   // to this GrpcMux in the order of Envoy's dependency ordering).
225:   std::list<std::string> subscription_ordering_;
226: 
227:   // Whether to enable the optimization of only including the node field in the very first
228:   // discovery request in an xDS gRPC stream (really just one: *not* per-type_url).
229:   const bool skip_subsequent_node_;
230: 
231:   // State to help with skip_subsequent_node's logic.
232:   bool any_request_sent_yet_in_current_stream_{};
233: 
234:   // Used to populate the (Delta)DiscoveryRequest's node field. That field is the same across
235:   // all type_urls, and moreover, the 'skip_subsequent_node' logic needs to operate across all
236:   // the type_urls. So, while the SubscriptionStates populate every other field of these messages,
237:   // this one is up to GrpcMux.
238:   const LocalInfo::LocalInfo& local_info_;
239:   Common::CallbackHandlePtr dynamic_update_callback_handle_;
240:   CustomConfigValidatorsPtr config_validators_;
241:   XdsConfigTrackerOptRef xds_config_tracker_;
242:   XdsResourcesDelegateOptRef xds_resources_delegate_;
243:   EdsResourcesCachePtr eds_resources_cache_;
244:   const std::string target_xds_authority_;
245: 
246:   // Used to track whether initial_resource_versions should be populated on the
247:   // next reconnection.
248:   bool should_send_initial_resource_versions_{true};
249: 
250:   bool started_{false};
251:   // True iff Envoy is shutting down; no messages should be sent on the `grpc_stream_` when this is
252:   // true because it may contain dangling pointers.
253:   std::atomic<bool> shutdown_{false};
254: };
