3: #include "source/common/common/logger.h"
4: #include "source/extensions/config_subscription/grpc/grpc_stream.h"
5: 
6: namespace Envoy {
7: namespace Config {
8: 
9: /**
10:  * This class arbitrates between two config providers of the same GrpcMux -
11:  * the primary and the failover. Envoy always prefers fetching config from the
12:  * primary source, but if not available, it will fetch the config from the failover
13:  * source until the primary is again available.
14:  *
15:  * This class owns the state for the GrpcMux primary and failover streams, and
16:  * proxies the gRPC-stream functionality to either the primary or the failover config sources.
17:  * The failover source is optional and will only be used if given in the c'tor.
18:  *
19:  * Failover is supported in both
20:  * SotW (RequestType = envoy::service::discovery::v3::DiscoveryRequest,
21:  *   ResponseType = envoy::service::discovery::v3::DiscoveryResponse), and
22:  * Delta-xDS (RequestType = envoy::service::discovery::v3::DeltaDiscoveryRequest,
23:  *   ResponseType = envoy::service::discovery::v3::DeltaDiscoveryResponse).
24:  * Both the primary and failover streams are either SotW or Delta-xDS.
25:  *
26:  * The use of this class will be as follows: the GrpcMux object will own an instance of
27:  * the GrpcMuxFailover. The GrpcMuxFailover will own 2 GrpcStreams, primary and failover.
28:  * Each of the primary and secondary streams will invoke GrpcStreamCallbacks
29:  * on their corresponding objects (also owned by the GrpcMuxFailover). These invocations
30:  * will be followed by the GrpcMuxFailover calling the GrpcStreamCallbacks on the GrpcMux
31:  * object that initialized it.
32:  *
33:  * To simplify the state-machine, Envoy can be in one of the mutually exclusive states:
34:  *   ConnectingToPrimary - attempting to connect to the primary source.
35:  *   ConnectedToPrimary - after receiving a response from the primary source.
36:  *   ConnectingToFailover - attempting to connect to the failover source.
37:  *   ConnectedToFailover - after receiving a response from the failover source.
38:  *   None - not attempting to connect or connected to any source (e.g., upon  initialization).
39:  *
40:  * The GrpcMuxFailover attempts to establish a connection to the primary source. Once a response is
41:  * received from the primary source it will be considered available, and the failover will not be
42:  * used. Any future reconnection attempts will be to the primary source only.
43:  * However, if no response is received from the primary source, and accessing the primary has
44:  * failed 2 times in a row, the GrpcMuxFailover will attempt to establish a connection to the
45:  * failover source. Envoy will keep alternating between the primary and failover sources attempting
46:  * to connect to one of them. If a response from the failover source is received, it will be the
47:  * source of configuration until the connection is closed. In case the failover connection is
48:  * closed, Envoy will attempt to connect to the primary, before retrying to connect to the failover
49:  * source. If the failover source is unavailable or a connection to it is closed, the
50:  * GrpcMuxFailover will alternate between attempts to reconnect to the primary source and the
51:  * failover source.
52:  * TODO(adisuissa): The number of consecutive failures is currently statically
53:  * defined, and may be converted to a config field in the future.
54:  */
55: template <class RequestType, class ResponseType>
56: class GrpcMuxFailover : public GrpcStreamInterface<RequestType, ResponseType>,
57:                         public Logger::Loggable<Logger::Id::config> {
58: public:
59:   static constexpr uint32_t DefaultFailoverBackoffMilliseconds = 500;
60: 
61:   // A GrpcStream creator function that receives the stream callbacks and returns a
62:   // GrpcStream object. This is introduced to facilitate dependency injection for
63:   // testing and will be used to create the primary and failover streams.
64:   using GrpcStreamCreator = std::function<GrpcStreamInterfacePtr<RequestType, ResponseType>(
65:       GrpcStreamCallbacks<ResponseType>* stream_callbacks)>;
66: 
67:   GrpcMuxFailover(GrpcStreamCreator primary_stream_creator,
68:                   absl::optional<GrpcStreamCreator> failover_stream_creator,
69:                   GrpcStreamCallbacks<ResponseType>& grpc_mux_callbacks,
70:                   Event::Dispatcher& dispatcher)
71:       : grpc_mux_callbacks_(grpc_mux_callbacks), primary_callbacks_(*this),
72:         primary_grpc_stream_(std::move(primary_stream_creator(&primary_callbacks_))),
73:         connection_state_(ConnectionState::None), ever_connected_to_primary_(false),
74:         previously_connected_to_(ConnectedTo::None) {
75:     ASSERT(primary_grpc_stream_ != nullptr);
76:     if (failover_stream_creator.has_value()) {
77:       ENVOY_LOG(warn, "Using xDS-Failover. Note that the implementation is currently considered "
78:                       "experimental and may be modified in future Envoy versions!");
79:       // Only create the retry timer if failover is supported.
80:       complete_retry_timer_ = dispatcher.createTimer([this]() -> void { retryConnections(); });
81:       failover_callbacks_ = std::make_unique<FailoverGrpcStreamCallbacks>(*this);
82:       GrpcStreamCreator& failover_stream_creator_ref = failover_stream_creator.value();
83:       failover_grpc_stream_ = std::move(failover_stream_creator_ref(failover_callbacks_.get()));
84:       ASSERT(failover_grpc_stream_ != nullptr);
85:     }
86:   }
87: 
88:   virtual ~GrpcMuxFailover() = default;
89: 
90:   // Attempts to establish a new stream to the either the primary or failover source.
91:   void establishNewStream() override {
92:     // Attempt establishing a connection to the primary source.
93:     // This method may be called multiple times, even if the primary/failover stream
94:     // is already established or in the process of being established.
95:     if (complete_retry_timer_) {
96:       complete_retry_timer_->disableTimer();
97:     }
98:     // If already connected to one of the source, return.
99:     if (connection_state_ == ConnectionState::ConnectedToPrimary ||
100:         connection_state_ == ConnectionState::ConnectedToFailover) {
101:       ENVOY_LOG_MISC(trace,
102:                      "Already connected to an xDS server, skipping establishNewStream() call");
103:       return;
104:     }
105:     if (!Runtime::runtimeFeatureEnabled(
106:             "envoy.reloadable_features.xds_failover_to_primary_enabled")) {
107:       // Allow stickiness, so if Envoy was ever connected to the primary source only
108:       // retry to reconnect to the primary source, If Envoy was ever connected to the
109:       // failover source then only retry to reconnect to the failover source.
110:       if (previously_connected_to_ == ConnectedTo::Primary) {
111:         ENVOY_LOG_MISC(
112:             info, "Previously connected to the primary xDS source, attempting to reconnect to it");
113:         connection_state_ = ConnectionState::ConnectingToPrimary;
114:         primary_grpc_stream_->establishNewStream();
115:         return;
116:       } else if (previously_connected_to_ == ConnectedTo::Failover) {
117:         ENVOY_LOG_MISC(
118:             info, "Previously connected to the failover xDS source, attempting to reconnect to it");
119:         connection_state_ = ConnectionState::ConnectingToFailover;
120:         failover_grpc_stream_->establishNewStream();
121:         return;
122:       }
123:     }
124:     // connection_state_ is either None, ConnectingToPrimary or
125:     // ConnectingToFailover. In the first 2 cases try to connect to the primary
126:     // (preferring the primary in the case of None), and in the third case
127:     // try to connect to the failover.
128:     // Note that if a connection to the primary source was ever successful, the
129:     // failover manager will keep setting connection_state_ to either None or
130:     // ConnectingToPrimary, which ensures that only the primary stream will be
131:     // established.
132:     if (connection_state_ == ConnectionState::ConnectingToFailover) {
133:       ASSERT(!ever_connected_to_primary_);
134:       failover_grpc_stream_->establishNewStream();
135:     } else {
136:       ASSERT(connection_state_ == ConnectionState::None ||
137:              connection_state_ == ConnectionState::ConnectingToPrimary);
138:       connection_state_ = ConnectionState::ConnectingToPrimary;
139:       primary_grpc_stream_->establishNewStream();
140:     }
141:   }
142: 
143:   // Returns the availability of the underlying stream.
144:   bool grpcStreamAvailable() const override {
145:     if (connectingToOrConnectedToFailover()) {
146:       return failover_grpc_stream_->grpcStreamAvailable();
147:     }
148:     // Either connecting/connected to the primary, or no connection was attempted.
149:     return primary_grpc_stream_->grpcStreamAvailable();
150:   }
