8: #include "envoy/grpc/async_client.h"
9: #include "envoy/grpc/status.h"
10: 
11: #include "source/common/common/backoff_strategy.h"
12: #include "source/common/common/token_bucket_impl.h"
13: #include "source/common/config/utility.h"
14: #include "source/common/grpc/typed_async_client.h"
15: #include "source/extensions/config_subscription/grpc/grpc_stream_interface.h"
16: 
17: namespace Envoy {
18: namespace Config {
19: 
20: template <class ResponseProto> using ResponseProtoPtr = std::unique_ptr<ResponseProto>;
21: 
22: // Oversees communication for gRPC xDS implementations (parent to both regular xDS and delta
23: // xDS variants). Reestablishes the gRPC channel when necessary, and provides rate limiting of
24: // requests.
25: template <class RequestProto, class ResponseProto>
26: class GrpcStream : public GrpcStreamInterface<RequestProto, ResponseProto>,
27:                    public Logger::Loggable<Logger::Id::config> {
28: public:
29:   // The entry value corresponding to the grpc stream's configuration entry index.
30:   enum class ConnectedStateValue {
31:     // The first entry in the config corresponds to the primary xDS source.
32:     FirstEntry = 1,
33:     // The second entry in the config corresponds to the failover xDS source.
34:     SecondEntry
35:   };
36: 
37:   GrpcStream(GrpcStreamCallbacks<ResponseProto>* callbacks,
38:              Grpc::RawAsyncClientSharedPtr&& async_client,
39:              const Protobuf::MethodDescriptor& service_method, Event::Dispatcher& dispatcher,
40:              Stats::Scope& scope, BackOffStrategyPtr backoff_strategy,
41:              const RateLimitSettings& rate_limit_settings, ConnectedStateValue connected_state_val)
42:       : callbacks_(callbacks), async_client_(std::move(async_client)),
43:         service_method_(service_method),
44:         control_plane_stats_(Utility::generateControlPlaneStats(scope)),
45:         time_source_(dispatcher.timeSource()), backoff_strategy_(std::move(backoff_strategy)),
46:         rate_limiting_enabled_(rate_limit_settings.enabled_),
47:         connected_state_val_(connected_state_val) {
48:     retry_timer_ = dispatcher.createTimer([this]() -> void { establishNewStream(); });
49:     if (rate_limiting_enabled_) {
50:       // Default Bucket contains 100 tokens maximum and refills at 10 tokens/sec.
51:       limit_request_ = std::make_unique<TokenBucketImpl>(
52:           rate_limit_settings.max_tokens_, time_source_, rate_limit_settings.fill_rate_);
53:       drain_request_timer_ = dispatcher.createTimer([this]() {
54:         if (stream_ != nullptr) {
55:           callbacks_->onWriteable();
56:         }
57:       });
58:     }
59:   }
60: 
61:   void establishNewStream() override {
62:     stream_intentionally_closed_ = false;
63:     ENVOY_LOG(debug, "Establishing new gRPC bidi stream to {} for {}", async_client_.destination(),
64:               service_method_.DebugString());
65:     if (stream_ != nullptr) {
66:       ENVOY_LOG(warn, "gRPC bidi stream to {} for {} already exists!", async_client_.destination(),
67:                 service_method_.DebugString());
68:       return;
69:     }
70:     stream_ = async_client_->start(service_method_, *this, Http::AsyncClient::StreamOptions());
71:     if (stream_ == nullptr) {
72:       ENVOY_LOG(debug, "Unable to establish new stream to configuration server {}",
73:                 async_client_.destination());
74:       callbacks_->onEstablishmentFailure(true);
75:       setRetryTimer();
76:       return;
77:     }
78:     control_plane_stats_.connected_state_.set(static_cast<uint64_t>(connected_state_val_));
79:     callbacks_->onStreamEstablished();
80:   }
81: 
82:   bool grpcStreamAvailable() const override { return stream_ != nullptr; }
83: 
84:   void sendMessage(const RequestProto& request) override { stream_->sendMessage(request, false); }
85: 
86:   // Grpc::AsyncStreamCallbacks
87:   void onCreateInitialMetadata(Http::RequestHeaderMap& metadata) override {
88:     UNREFERENCED_PARAMETER(metadata);
89:   }
90: 
91:   void onReceiveInitialMetadata(Http::ResponseHeaderMapPtr&& metadata) override {
92:     UNREFERENCED_PARAMETER(metadata);
93:   }
94: 
95:   void onReceiveMessage(ResponseProtoPtr<ResponseProto>&& message) override {
96:     // Reset here so that it starts with fresh backoff interval on next disconnect.
97:     backoff_strategy_->reset();
98:     // Clear here instead of on stream establishment in case streams are immediately closed
99:     // repeatedly.
100:     clearCloseStatus();
101:     // Sometimes during hot restarts this stat's value becomes inconsistent and will continue to
102:     // have 0 until it is reconnected. Setting here ensures that it is consistent with the state of
103:     // management server connection.
104:     control_plane_stats_.connected_state_.set(static_cast<uint64_t>(connected_state_val_));
105:     callbacks_->onDiscoveryResponse(std::move(message), control_plane_stats_);
106:   }
107: 
108:   void onReceiveTrailingMetadata(Http::ResponseTrailerMapPtr&& metadata) override {
109:     UNREFERENCED_PARAMETER(metadata);
110:   }
111: 
112:   void onRemoteClose(Grpc::Status::GrpcStatus status, const std::string& message) override {
113:     logClose(status, message);
114:     stream_ = nullptr;
115:     control_plane_stats_.connected_state_.set(0);
116:     // By default Envoy will reconnect to the same server, so pass true here.
117:     // This will be overridden by the mux-failover if Envoy will reconnect to a
118:     // different server.
119:     callbacks_->onEstablishmentFailure(true);
120:     // Only retry the timer if not intentionally closed by Envoy.
121:     if (!stream_intentionally_closed_) {
122:       setRetryTimer();
123:     }
124:   }
125: 
126:   void maybeUpdateQueueSizeStat(uint64_t size) override {
127:     // Although request_queue_.push() happens elsewhere, the only time the queue is non-transiently
128:     // non-empty is when it remains non-empty after a drain attempt. (The push() doesn't matter
129:     // because we always attempt this drain immediately after the push). Basically, a change in
130:     // queue length is not "meaningful" until it has persisted until here. We need the
131:     // if(>0 || used) to keep this stat from being wrongly marked interesting by a pointless set(0)
132:     // and needlessly taking up space. The first time we set(123), used becomes true, and so we will
133:     // subsequently always do the set (including set(0)).
134:     if (size > 0 || control_plane_stats_.pending_requests_.used()) {
135:       control_plane_stats_.pending_requests_.set(size);
136:     }
137:   }
138: 
139:   bool checkRateLimitAllowsDrain() override {
140:     if (!rate_limiting_enabled_ || limit_request_->consume(1, false)) {
141:       return true;
142:     }
143:     ASSERT(drain_request_timer_ != nullptr);
144:     control_plane_stats_.rate_limit_enforced_.inc();
145:     // Enable the drain request timer.
146:     if (!drain_request_timer_->enabled()) {
147:       drain_request_timer_->enableTimer(limit_request_->nextTokenAvailable());
148:     }
149:     return false;
150:   }
